export const replayAttackActionSchema = z
  .object({
    attacker: z.string().min(1),
    target: z.string().min(1),
    damage: z.number().int().positive(),
    deckDamage: z.number().int().nonnegative().default(0),
    targetRemoved: z.boolean().default(false)
